    const int64_t n = x->GetDim(0);
    const int64_t h = x->GetDim(2);
    const int64_t w_in = x->GetDim(3);
    const int64_t k = w->GetDim(2);
    gert::Shape *y = context->GetOutputShape(0);
    const int64_t hOut = h - k + 1;
    const int64_t wOut = w_in - k + 1;
    y->SetDimNum(4);
    y->SetDim(0, n);
    y->SetDim(1, 1);
    y->SetDim(2, hOut);
    y->SetDim(3, wOut);
    return GRAPH_SUCCESS;
}

